#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int a[3][3];
        for (int i = 0; i < 3; ++i) {
            scanf("%d %d %d", &a[i][0], &a[i][1], &a[i][2]);
        }
        // direct swaps
        int swap01 = (a[0][1] < a[1][0]) ? a[0][1] : a[1][0];
        a[0][1] -= swap01; a[1][0] -= swap01;
        int swap02 = (a[0][2] < a[2][0]) ? a[0][2] : a[2][0];
        a[0][2] -= swap02; a[2][0] -= swap02;
        int swap12 = (a[1][2] < a[2][1]) ? a[1][2] : a[2][1];
        a[1][2] -= swap12; a[2][1] -= swap12;
        int direct = swap01 + swap02 + swap12;
        // remaining misplaced balls
        int rem = 0;
        for (int i = 0; i < 3; ++i) {
            for (int j = 0; j < 3; ++j) if (i != j) rem += a[i][j];
        }
        int ans = direct + 2 * (rem / 3);
        printf("%d\n", ans);
    }
    return 0;
}

