                st = new StringTokenizer(br.readLine());
                a[i][0] = Integer.parseInt(st.nextToken());
                a[i][1] = Integer.parseInt(st.nextToken());
                a[i][2] = Integer.parseInt(st.nextToken());
            }
            int swap01 = Math.min(a[0][1], a[1][0]);
            a[0][1] -= swap01; a[1][0] -= swap01;
            int swap02 = Math.min(a[0][2], a[2][0]);
            a[0][2] -= swap02; a[2][0] -= swap02;
            int swap12 = Math.min(a[1][2], a[2][1]);
            a[1][2] -= swap12; a[2][1] -= swap12;
            int direct = swap01 + swap02 + swap12;
            int rem = 0;
            for (int i = 0; i < 3; i++)
                for (int j = 0; j < 3; j++)
                    if (i != j) rem += a[i][j];
            int ans = direct + 2 * (rem / 3);
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
